import React from 'react';

function DishePresentationSheet({ title, prepTime, image, onSelect }) {
    return (
        <article className="fiche-plat border rounded p-4 shadow-sm max-w-md">
            {image && (
                <img
                    src={image}
                    alt={title}
                    style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: 6 }}
                />
            )}
            <div style={{ paddingTop: 12 }}>
                <h2 style={{ margin: 0, fontSize: 20 }}>{title}</h2>
                {prepTime && <p style={{ margin: '6px 0', color: '#555' }}>Temps de préparation: {prepTime}</p>}
                <button
                    onClick={onSelect}
                    style={{ marginTop: 8, padding: '8px 12px', cursor: 'pointer' }}
                >
                    Voir la recette
                </button>
            </div>
        </article>
    );
}

export default dishePresentationSheet;
